class Solution:
    def minDiffInBST(self, root):
        vals = []
        def walk(node):
            if not node:
                return
            walk(node.left)
            vals.append(node.val)
            walk(node.right)
        walk(root)
        best = None
        for i in range(1, len(vals)):
            d = vals[i] - vals[i - 1]
            if best is None or d < best:
                best = d
        return best

