class Solution:
    def minDiffInBST(self, root):
        self.prev = None
        self.best = float('inf')
        def walk(node):
            if not node:
                return
            walk(node.left)
            if self.prev is not None:
                self.best = min(self.best, node.val - self.prev)
            self.prev = node.val
            walk(node.right)
        walk(root)
        return self.best

