var minDiffInBST = function(root) {
    let prev = null;
    let best = Infinity;
    function walk(node) {
        if (!node) return;
        walk(node.left);
        if (prev !== null) best = Math.min(best, node.val - prev);
        prev = node.val;
        walk(node.right);
    }
    walk(root);
    return best;
};
